def validate_xml(xml_data):
    try:
        # Parse the XML data
        root = ET.fromstring(xml_data)
        
        # Check if the root element is not None
        if root is None:
            return False, "Invalid XML format"
        
        # Perform additional validation logic here (e.g., check for specific tags, attributes, etc.)
        # Example: Ensure there is at least one 'item' tag
        if len(root.findall('.//item')) == 0:
            return False, "No 'item' elements found in the XML"
        
        return True, "XML is valid"
    
    except ET.ParseError as e:
        return False, f"XML parsing error: {e}"
    
    except Exception as e:
        return False, f"An unexpected error occurred: {e}"

